function getWeekRange(){
  const now = new Date();
  const day = now.getDay();
  const mon = new Date(now); mon.setDate(now.getDate() - (day===0?6:day-1)); mon.setHours(0,0,0,0);
  const sun = new Date(mon); sun.setDate(mon.getDate()+6); sun.setHours(23,59,59,999);
  return {mon, sun};
}
function getMonthRange(){
  const now = new Date();
  const start = new Date(now.getFullYear(), now.getMonth(), 1);
  const end = new Date(now.getFullYear(), now.getMonth()+1, 0); end.setHours(23,59,59,999);
  return {start, end};
}
function countSessions(history, from, to){
  return (history||[]).filter(e=>{
    const parts = e.date.split("/");
    if(parts.length!==3) return false;
    const d = new Date(parseInt(parts[2]), parseInt(parts[1])-1, parseInt(parts[0]));
    return d>=from && d<=to;
  }).length;
}
function getClientCalendarSessions(clientName, daysAhead=120, eventsOverride=null){
  if(!clientName) return [];
  const fullName = clientName.trim().toLowerCase();
  const now = new Date(); now.setHours(0,0,0,0);
  const end = new Date(now); end.setDate(now.getDate()+daysAhead);
  const eventsToCheck = eventsOverride || BOOKED_EVENTS;
  return eventsToCheck
    .filter(ev => {
      if(!ev.title) return false;
      const title = ev.title.trim().toLowerCase();
      // Exact full-name match only (avoids collisions like "Martin" vs "Martin Sok")
      if(title !== fullName) return false;
      const s = new Date(ev.start);
      return s >= now && s <= end;
    })
    .map(ev => {
      const s = new Date(ev.start), e = new Date(ev.end);
      return {
        dateISO: ev.start,
        date: formatDate(s),
        time: formatTime(s),
        timeEnd: formatTime(e),
        source: "calendar",
      };
    })
    .sort((a,b)=>new Date(a.dateISO)-new Date(b.dateISO));
}

function getUpcomingSessions(requests, bookedEvents, daysAhead=30){
  const now = new Date(); now.setHours(0,0,0,0);
  const end = new Date(now); end.setDate(now.getDate()+daysAhead);
  // From approved requests
  const fromReqs = requests
    .filter(r=>r.status==="approved")
    .map(r=>({name:r.name,phone:r.phone,dateISO:r.dateISO,date:r.date,time:r.time,timeEnd:r.timeEnd,source:"request"}))
    .filter(r=>{ const d=new Date(r.dateISO); return d>=now&&d<=end; });
  return fromReqs.sort((a,b)=>new Date(a.dateISO)-new Date(b.dateISO));
}
function isWeekend(d){const day=d.getDay();return day===0||day===6;}
function getHours(d){return isWeekend(d)?WORKING_HOURS.weekend:WORKING_HOURS.weekday;}
function formatTime(d){const h=d.getHours();return `${h<10?"0"+h:h}:00`;}
function formatDate(d){return `${DAYS_FULL[d.getDay()]}, ${d.getDate()} ${MONTHS[d.getMonth()]} ${d.getFullYear()}`;}

function tgSortValue(code){
  if(!code) return Infinity; // clients with no code sort to the end
  const match = code.match(/(\d+)/);
  return match ? parseInt(match[1], 10) : Infinity;
}

function countApprovedThisMonth(requests, identifier){
  const now = new Date();
  const month = now.getMonth(), year = now.getFullYear();
  return requests.filter(r=>{
    if(r.status!=="approved") return false;
    const matches = (identifier.clientCode && r.clientCode && r.clientCode.toUpperCase()===identifier.clientCode.toUpperCase())
      || r.phone===identifier.phone;
    if(!matches) return false;
    const d = new Date(r.dateISO);
    return d.getMonth()===month && d.getFullYear()===year;
  }).length;
}

function generateSlots(date, trainerId="johan", eventsOverride=null){
  const trainer = TRAINERS.find(t=>t.id===trainerId) || TRAINERS[0];
  const hours = getTrainerSlotsForDay(trainer, date);
  const eventsToCheck = eventsOverride || BOOKED_EVENTS;
  const slots = [];
  for(const h of hours){
    const s=new Date(date);s.setHours(h,0,0,0);
    const e=new Date(date);e.setHours(h+1,0,0,0);
    // Only Johan's slots check against the real Google Calendar sync
    const booked = trainerId==="johan"
      ? eventsToCheck.some(b=>new Date(b.start)<e&&new Date(b.end)>s)
      : false;
    slots.push({time:s,endTime:e,key:`${trainerId}-${s.toISOString()}`,booked,trainerId});
  }
  return slots;
}

