                  if(sorted.length===0) return <div style={{textAlign:"center",padding:"40px 0",color:"#a89878",fontFamily:"'Cinzel',serif",letterSpacing:2,fontSize:10}}>{clients.length===0?"NO CLIENTS YET":"NO RESULTS"}</div>;
